package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import org.junit.jupiter.api.Test;

class LineItemTest {

  @Test
  void getPriceInMicros_returnsCorrectValue() throws Exception {
    String name = "TestItem";
    int quantity = 2;
    long priceInMicros = 123456L;
    String currencyCode = "USD";

    // Directly use LineItem class instead of reflection to avoid ClassNotFoundException
    LineItem lineItem = new LineItem(name, quantity, priceInMicros, currencyCode);

    long result = lineItem.getPriceInMicros();

    assertEquals(priceInMicros, result);
  }
}
